    Edge *edges;
} Graph;

// Function to read the input graph
Graph readGraph() {
    Graph graph;
    scanf("%d %d", &graph.n, &graph.m);
    graph.edges = (Edge *)malloc(graph.m * sizeof(Edge));
    for (int i = 0; i < graph.m; i++) {
        scanf("%d %d", &graph.edges[i].u, &graph.edges[i].v);
    }
    return graph;
}

// Function to check if it is possible to make all pairs of nodes good by adding at most one edge
int check(Graph graph) {
    // Perform DFS to find all biconnected components and bridges
    int *low = (int *)malloc(graph.n * sizeof(int));
    int *disc = (int *)malloc(graph.n * sizeof(int));
    int *parent = (int *)malloc(graph.n * sizeof(int));
    int *visited = (int *)malloc(graph.n * sizeof(int));
    int time = 0;
    int bridgeCount = 0;
    for (int i = 0; i < graph.n; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph.n; i++) {
        if (!visited[i]) {
            bridgeCount += dfs(graph, i, -1, low, disc, parent, visited, &time);
        }
    }
    free(low);
    free(disc);
    free(parent);
    free(visited);
    return bridgeCount <= 1;
}

// Function to perform DFS
int dfs(Graph graph, int u, int parent, int *low, int *disc, int *parentArr, int *visited, int *time) {
    visited[u] = 1;
    disc[u] = *time;
    low[u] = *time;
    (*time)++;
    int bridgeCount = 0;
    for (int i = 0; i < graph.m; i++) {
        int v = graph.edges[i].v;
        if (graph.edges[i].u == u) {
            if (!visited[v]) {
                parentArr[v] = u;
                bridgeCount += dfs(graph, v, u, low, disc, parentArr, visited, time);
                low[u] = min(low[u], low[v]);
                if (low[v] > disc[u]) {
                    bridgeCount++;
                }
            } else if (v != parent) {
                low[u] = min(low[u], disc[v]);
            }
        }
    }
    return bridgeCount;
}

// Function to find the minimum of two integers
