import java.util.Scanner;
import java.util.ArrayList;
import java.util.List;
public class Main {
    // Define the structure for an edge
    static class Edge {
        int u, v;
        public Edge(int u, int v) {
            this.u = u;
            this.v = v;
        }
    }

    // Define the structure for a graph
    static class Graph {
        int n, m;
        List<Edge> edges;
        public Graph(int n, int m) {
            this.n = n;
            this.m = m;
            this.edges = new ArrayList<>();
        }
    }

    // Function to read the input graph
    public static Graph readGraph(Scanner scanner) {
        Graph graph = new Graph(scanner.nextInt(), scanner.nextInt());
        for (int i = 0; i < graph.m; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            graph.edges.add(new Edge(u, v));
        }
        return graph;
    }

    // Function to check if it is possible to make all pairs of nodes good by adding at most one edge
    public static boolean check(Graph graph) {
        // Perform DFS to find all biconnected components and bridges
        int[] low = new int[graph.n];
        int[] disc = new int[graph.n];
        int[] parent = new int[graph.n];
        boolean[] visited = new boolean[graph.n];
        int time = 0;
        int bridgeCount = 0;
        for (int i = 0; i < graph.n; i++) {
            if (!visited[i]) {
                bridgeCount += dfs(graph, i, -1, low, disc, parent, visited, time);
            }
        }
        return bridgeCount <= 1;
    }

    // Function to perform DFS
    public static int dfs(Graph graph, int u, int parent, int[] low, int[] disc, int[] parentArr, boolean[] visited, int time) {
        visited[u] = true;
        disc[u] = time;
        low[u] = time;
        time++;
        int bridgeCount = 0;
        for (Edge edge : graph.edges) {
            int v = edge.v;
            if (edge.u == u) {
                if (!visited[v]) {
                    parentArr[v] = u;
                    bridgeCount += dfs(graph, v, u, low, disc, parentArr, visited, time);
                    low[u] = Math.min(low[u], low[v]);
                    if (low[v] > disc[u]) {
                        bridgeCount++;
                    }
                } else if (v != parent) {
                    low[u] = Math.min(low[u], disc[v]);
                }
            }
        }
        return bridgeCount;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            Graph graph = readGraph(scanner);
            if (check(graph)) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}
